import { describe, expect, it } from "vitest";
import { createBangIndex, findBangInvocation, parseHeliumBangList, resolveBangQuery } from "../../src/utils/bang-resolver";

const fixture = `
// Generated by Helium
[
  {
    "s": "Google",
    "ts": ["g", "google",],
    "u": "https://www.google.com/search?q={searchTerms}",
  },
  {
    "s": "GitHub",
    "ts": ["gh", "git", "github"],
    "u": "https://github.com/search?q={searchTerms}",
  },
  {
    "s": "ChatGPT",
    "ts": ["chatgpt"],
    "u": "https://chatgpt.com/?prompt={searchTerms}",
    "sc": "ai",
  },
]
`;

describe("Helium bang resolver", () => {
  const index = createBangIndex(parseHeliumBangList(fixture));

  it("parses comments and trailing commas", () => {
    expect([...index.keys()]).toEqual(["g", "google", "gh", "git", "github", "chatgpt"]);
  });

  it("resolves leading bang queries", () => {
    expect(resolveBangQuery("!gh raycast extensions", index)).toMatchObject({
      name: "GitHub",
      trigger: "gh",
      query: "raycast extensions",
      url: "https://github.com/search?q=raycast%20extensions",
    });
  });

  it("resolves trailing bang queries", () => {
    expect(resolveBangQuery("large language models !g", index)?.url).toBe(
      "https://www.google.com/search?q=large%20language%20models",
    );
  });

  it("encodes search terms exactly once", () => {
    expect(resolveBangQuery("C++ site:example.com !g", index)?.url).toBe(
      "https://www.google.com/search?q=C%2B%2B%20site%3Aexample.com",
    );
  });

  it("does not resolve unknown or non-token bangs", () => {
    expect(resolveBangQuery("what is !important", index)).toBeUndefined();
    expect(resolveBangQuery("hello!", index)).toBeUndefined();
    expect(resolveBangQuery("!!g query", index)).toBeUndefined();
  });

  it("extracts bang invocation case-insensitively", () => {
    expect(findBangInvocation("  !G  test  ")).toEqual({ trigger: "g", query: "test" });
  });
});
